patch:
--- a/multiplexer_8bit.v
+++ b/multiplexer_8bit.v
@@ -8,7 +8,7 @@
    input [7:0] data_in,
    output reg [7:0] data_out
  );
-  always @(sel) begin
+  always @(sel or data_in) begin
     case (sel)
       1'b0: data_out = 8'h00;
       1'b1: data_out = data_in;

before_code:
module multiplexer_8bit (
  input clk,
  input sel,
  input [7:0] data_in,
  output reg [7:0] data_out
);
  always @(sel) begin
    case (sel)
      1'b0: data_out = 8'h00;
      1'b1: data_out = data_in;
    endcase
  end
endmodule

after_code:
module multiplexer_8bit (
  input clk,
  input sel,
  input [7:0] data_in,
  output reg [7:0] data_out
);
  always @(sel or data_in) begin
    case (sel)
      1'b0: data_out = 8'h00;
      1'b1: data_out = data_in;
    endcase
  end
endmodule
